func GetDefaultClientConf() ClientCommonConf {
	return ClientCommonConf{
		ClientConfig:			legacyauth.GetDefaultClientConf(),
		TCPMux:				true,
		LoginFailExit:			true,
		Protocol:			"tcp",
		Start:				make([]string, 0),
		TLSEnable:			true,
		DisableCustomTLSFirstByte:	true,
		Metas:				make(map[string]string),
		IncludeConfigFiles:		make([]string, 0),
	}
}
